function escapeHtml(str){
  return String(str)
    .replaceAll('&','&amp;')
    .replaceAll('<','&lt;')
    .replaceAll('>','&gt;')
    .replaceAll('"','&quot;')
    .replaceAll("'", '&#39;');
}
function clamp(n, min, max){ return Math.min(max, Math.max(min, n)); }
function hexToRgb(hex){
  const clean = hex.replace('#','');
  const int = parseInt(clean, 16);
  return { r:(int>>16)&255, g:(int>>8)&255, b:int&255 };
}
function shade(hex, amount){
  const {r,g,b} = hexToRgb(hex);
  const adj = (v) => clamp(Math.round(v + (amount/100)*255), 0, 255);
  return `rgb(${adj(r)}, ${adj(g)}, ${adj(b)})`;
}
function luminance(hex){
  const {r,g,b}=hexToRgb(hex);
  const v=[r,g,b].map(c=>{
    c/=255;
    return c<=0.03928 ? c/12.92 : Math.pow((c+0.055)/1.055,2.4);
  });
  return 0.2126*v[0]+0.7152*v[1]+0.0722*v[2];
}
function textOn(hex){
  return luminance(hex) > 0.58 ? '#1b2432' : '#ffffff';
}
function formatNumber(n){
  return Number(n).toLocaleString();
}
function colorSwatch(colorHex, title=''){
  return `<span class="swatch" style="background:${colorHex}" title="${escapeHtml(title)}"></span>`;
}
function studsMarkup(count, x, y, fill, stroke, opacity){
  let out = '';
  for (let i=0;i<count;i++){
    const cx = x + i * 10;
    out += `<circle cx="${cx}" cy="${y}" r="3.2" fill="${fill}" stroke="${stroke}" stroke-width="0.8" opacity="${opacity}"></circle>`;
  }
  return out;
}
