function cabinetMinimapSvg(cabinet, drawerCode) {
  const row = drawerCode.charAt(0).toUpperCase();
  const col = parseInt(drawerCode.slice(1));
  const isRed = cabinet.toLowerCase() === 'red';
  const cabBg = isRed ? '#8c1118' : '#111111';
  
  let out = `<svg viewBox="-6 -6 90 92" width="64" height="64" style="flex:none; border-radius:8px; filter:drop-shadow(0 4px 6px rgba(0,0,0,0.1))">`;
  out += `<rect x="-6" y="-6" width="90" height="92" rx="4" fill="${cabBg}" />`;
  
  let y = 0;
  ['A','B','C','D'].forEach(r => {
    for (let c = 1; c <= 8; c++) {
      const active = (r === row && c === col);
      out += `<rect x="${(c-1)*10}" y="${y}" width="8" height="8" rx="1.5" fill="${active ? '#38bdf8' : 'rgba(255,255,255,0.15)'}" />`;
    }
    y += 10;
  });
  
  y += 2;
  ['E','F','G'].forEach(r => {
    for (let c = 1; c <= 4; c++) {
       const active = (r === row && c === col);
       out += `<rect x="${(c-1)*20}" y="${y}" width="18" height="12" rx="2" fill="${active ? '#38bdf8' : 'rgba(255,255,255,0.15)'}" />`;
    }
    y += 14;
  });
  
  out += `</svg>`;
  return out;
}

function fallbackPartSvg(part){
  const fill = part.color_hex;
  const top = shade(fill, 18);
  const stroke = shade(fill, -24);
  const shadow = shade(fill, -12);
  const opacity = part.color.startsWith('Trans-') ? 0.58 : 1;
  const len = clamp(Math.round(part.length || 1), 1, 6);
  const baseW = clamp(18 + len * 5, 18, 48);
  const x = Math.round((64 - baseW) / 2);
  const label = `${part.description} (${part.color})`;
  const shape = part.shape_key;
  const showStuds = !shape.includes('tile') && !shape.includes('bar') && !shape.includes('cone') && !shape.includes('panel') && !shape.includes('ingot') && !shape.includes('accessory');
  if (shape === 'bar' || shape === 'accessory') {
    const y = shape === 'accessory' ? 26 : 24;
    return `<svg viewBox="0 0 64 48" role="img" aria-label="${escapeHtml(label)}">
      <line x1="12" y1="${y}" x2="52" y2="${y}" stroke="${fill}" stroke-width="${shape === 'accessory' ? 6 : 5}" stroke-linecap="round" opacity="${opacity}"></line>
      <line x1="12" y1="${y}" x2="52" y2="${y}" stroke="${stroke}" stroke-width="1.4" stroke-linecap="round" opacity="${opacity}"></line>
      <circle cx="18" cy="${y}" r="${shape === 'accessory' ? 4.4 : 3.4}" fill="${top}" stroke="${stroke}" stroke-width="0.8" opacity="${opacity}"></circle>
      <circle cx="46" cy="${y}" r="${shape === 'accessory' ? 3.2 : 2.4}" fill="${top}" stroke="${stroke}" stroke-width="0.8" opacity="${opacity}"></circle>
    </svg>`;
  }
  if (shape === 'cone') {
    return `<svg viewBox="0 0 64 48" role="img" aria-label="${escapeHtml(label)}">
      <ellipse cx="32" cy="35" rx="15" ry="5.5" fill="${shadow}" stroke="${stroke}" stroke-width="1" opacity="${opacity}"></ellipse>
      <path d="M22 34 L29 14 Q32 10 35 14 L42 34 Z" fill="${fill}" stroke="${stroke}" stroke-width="1.1" opacity="${opacity}"></path>
      <ellipse cx="32" cy="34" rx="10" ry="3.2" fill="${top}" stroke="${stroke}" stroke-width="0.8" opacity="${opacity}"></ellipse>
    </svg>`;
  }
  if (shape === 'panel') {
    return `<svg viewBox="0 0 64 48" role="img" aria-label="${escapeHtml(label)}">
      <rect x="18" y="12" width="28" height="24" rx="4" fill="${fill}" stroke="${stroke}" stroke-width="1.1" opacity="${opacity}"></rect>
      <rect x="24" y="18" width="16" height="12" rx="2" fill="rgba(255,255,255,0.28)" stroke="${stroke}" stroke-width="0.9" opacity="${opacity}"></rect>
      <rect x="16" y="34" width="32" height="4" rx="2" fill="${shadow}" opacity="${opacity}"></rect>
    </svg>`;
  }
  if (shape === 'bracket') {
    return `<svg viewBox="0 0 64 48" role="img" aria-label="${escapeHtml(label)}">
      <path d="M18 13 H46 V22 H33 V35 H18 Z" fill="${fill}" stroke="${stroke}" stroke-width="1.1" opacity="${opacity}"></path>
      <path d="M19 14 H45 V18 H29 V34 H19 Z" fill="${top}" opacity="0.45"></path>
      <circle cx="25" cy="18" r="3" fill="${top}" stroke="${stroke}" stroke-width="0.7" opacity="${opacity}"></circle>
      <circle cx="39" cy="18" r="3" fill="${top}" stroke="${stroke}" stroke-width="0.7" opacity="${opacity}"></circle>
      <circle cx="25" cy="29" r="3" fill="${top}" stroke="${stroke}" stroke-width="0.7" opacity="${opacity}"></circle>
    </svg>`;
  }
  if (shape === 'slope') {
    return `<svg viewBox="0 0 64 48" role="img" aria-label="${escapeHtml(label)}">
      <polygon points="14,34 48,34 42,18 22,18" fill="${fill}" stroke="${stroke}" stroke-width="1.1" opacity="${opacity}"></polygon>
      <polygon points="22,18 42,18 38,14 26,14" fill="${top}" opacity="0.55"></polygon>
      <circle cx="25" cy="19" r="2.8" fill="${top}" stroke="${stroke}" stroke-width="0.7" opacity="${opacity}"></circle>
      <circle cx="37" cy="19" r="2.8" fill="${top}" stroke="${stroke}" stroke-width="0.7" opacity="${opacity}"></circle>
    </svg>`;
  }
  if (shape === 'wedge') {
    const left = /left/i.test(part.description);
    const points = left ? "14,35 47,35 35,18 14,18" : "17,35 50,35 50,18 29,18";
    return `<svg viewBox="0 0 64 48" role="img" aria-label="${escapeHtml(label)}">
      <polygon points="${points}" fill="${fill}" stroke="${stroke}" stroke-width="1.1" opacity="${opacity}"></polygon>
      <polygon points="${left ? '15,18 35,18 28,14 15,14' : '29,18 49,18 49,14 36,14'}" fill="${top}" opacity="0.5"></polygon>
      <circle cx="${left ? '22' : '42'}" cy="20" r="3" fill="${top}" stroke="${stroke}" stroke-width="0.7" opacity="${opacity}"></circle>
    </svg>`;
  }
  if (shape === 'round-brick' || shape === 'round-plate' || shape === 'round-tile') {
    const ry = shape === 'round-brick' ? 12 : shape === 'round-plate' ? 10 : 9;
    return `<svg viewBox="0 0 64 48" role="img" aria-label="${escapeHtml(label)}">
      <ellipse cx="32" cy="28" rx="15" ry="${ry}" fill="${fill}" stroke="${stroke}" stroke-width="1.1" opacity="${opacity}"></ellipse>
      <ellipse cx="32" cy="22" rx="14" ry="${Math.max(4.5, ry-5)}" fill="${top}" opacity="0.55"></ellipse>
      ${shape !== 'round-tile' ? `<circle cx="32" cy="22" r="4" fill="${top}" stroke="${stroke}" stroke-width="0.7" opacity="${opacity}"></circle>` : ''}
    </svg>`;
  }
  if (shape === 'ingot') {
    return `<svg viewBox="0 0 64 48" role="img" aria-label="${escapeHtml(label)}">
      <path d="M17 31 L22 18 H42 L47 31 Z" fill="${fill}" stroke="${stroke}" stroke-width="1.1" opacity="${opacity}"></path>
      <path d="M22 18 H42 L38 14 H26 Z" fill="${top}" opacity="0.55"></path>
    </svg>`;
  }

  const height = shape === 'brick' ? 18 : shape === 'plate' ? 12 : 10;
  const y = 31 - height/2;
  const studCount = showStuds ? clamp(Math.round(part.length || 1), 1, 4) : 0;
  return `<svg viewBox="0 0 64 48" role="img" aria-label="${escapeHtml(label)}">
    <rect x="${x}" y="${y}" width="${baseW}" height="${height}" rx="5" fill="${fill}" stroke="${stroke}" stroke-width="1.1" opacity="${opacity}"></rect>
    <rect x="${x+2}" y="${y+2}" width="${baseW-4}" height="${Math.max(4, Math.min(6, height/2))}" rx="3" fill="${top}" opacity="0.45"></rect>
    ${studCount ? studsMarkup(studCount, x + 8, y + 4.5, top, stroke, opacity) : ''}
  </svg>`;
}

function partSvg(part){
  const colorId = rebrickableColors[part.color] !== undefined ? rebrickableColors[part.color] : 0;
  const url = `https://cdn.rebrickable.com/media/parts/ldraw/${colorId}/${part.part_number}.png`;
  return `
    <img class="part-isometric-img" src="${url}" alt="${escapeHtml(part.description)}" loading="lazy"
         onerror="this.style.display='none'; this.nextElementSibling.style.display='block';">
    <div class="part-fallback-svg">
      ${fallbackPartSvg(part)}
    </div>
  `;
}
function buildDrawerButton(drawer){
  return `<button class="drawer ${drawer.size}" data-drawer="${drawer.drawer_key}" style="--drawer-accent:${drawer.group_color}" title="${escapeHtml(drawer.group)} · ${drawer.total_types} lots · ${drawer.total_qty} pieces">
    <span class="drawer-accent"></span>
    <div class="drawer-top">
      <span class="drawer-id">${escapeHtml(drawer.row + String(drawer.col))}</span>
      <span class="drawer-size">${drawer.size}</span>
    </div>
    <div class="drawer-group">${escapeHtml(groupShort[drawer.group] || drawer.group)}</div>
    <div class="drawer-meta">${formatNumber(drawer.total_types)} lots · ${formatNumber(drawer.total_qty)} pcs</div>
  </button>`;
}
function renderCabinet(cabinet){
  const container = document.getElementById(`${cabinet.toLowerCase()}-cabinet`);
  const cabinetDrawers = drawersData
    .filter(d => d.cabinet === cabinet)
    .sort((a,b) => rowOrder[a.row] - rowOrder[b.row] || a.col - b.col);

  const rows = ['A','B','C','D','E','F','G'];
  let html = '';
  for (const row of rows){
    const rowDrawers = cabinetDrawers.filter(d => d.row === row);
    html += `<div class="cabinet-row-wrap">
      <div class="row-label">${row}</div>
      <div class="cabinet-row ${rowOrder[row] <= 4 ? 'small-row' : 'large-row'}">
        ${rowDrawers.map(buildDrawerButton).join('')}
      </div>
    </div>`;
  }
  container.innerHTML = html;
  container.querySelectorAll('.drawer').forEach(btn => {
    btn.addEventListener('click', () => selectDrawer(btn.dataset.drawer));
  });
}
function setTab(tabName){
  activeTab = tabName;
  document.querySelectorAll('.tab').forEach(btn => {
    const isActive = btn.dataset.tab === tabName;
    btn.classList.toggle('active', isActive);
    btn.setAttribute('aria-selected', String(isActive));
  });
  document.getElementById('cabinet-panel').classList.toggle('active', tabName === 'cabinet');
  document.getElementById('parts-panel').classList.toggle('active', tabName === 'parts');
}
function drawLoadLabel(pct){
  if (pct >= 140) return 'dense outlier';
  if (pct >= 115) return 'slightly dense';
  if (pct >= 85) return 'balanced';
  if (pct >= 60) return 'slightly light';
  return 'light / specialty';
}
function renderDrawerDetail(drawerKey){
  const drawer = drawersByKey.get(drawerKey);
  if (!drawer) return;
  const parts = partsByDrawer.get(drawerKey) || [];
  const fillWidth = clamp(drawer.load_pct, 0, 100);
  const detail = document.getElementById('drawer-detail');
  const noteHtml = drawer.note ? `<div class="drawer-note">${escapeHtml(drawer.note)}</div>` : '';
  const partRows = parts.map(part => `
    <button class="detail-part ${selectedPartId === part.part_id ? 'selected' : ''}" data-part-id="${part.part_id}">
      <div class="icon-shell">${partSvg(part)}</div>
      <div>
        <div class="detail-name">${escapeHtml(part.description)}</div>
        <div class="detail-meta">${colorSwatch(part.color_hex, part.color)}${escapeHtml(part.color)} · Qty ${formatNumber(part.qty)} · Part ${escapeHtml(part.part_number)}</div>
      </div>
      <div class="badge mono">#${escapeHtml(part.part_number)}</div>
    </button>
  `).join('');
  detail.innerHTML = `
    <div class="detail-top">
      <div>
        <div class="detail-title">${escapeHtml(drawer.drawer_code)}</div>
        <div class="detail-sub">${escapeHtml(drawer.cabinet)} cabinet · ${escapeHtml(groupShort[drawer.group] || drawer.group)} · ${drawer.size} drawer</div>
      </div>
    </div>
    <div class="badge-row">
      <span class="badge"><span class="swatch" style="background:${drawer.group_color}"></span>${escapeHtml(drawer.group)}</span>
      <span class="badge">${formatNumber(drawer.total_types)} lots</span>
      <span class="badge">${formatNumber(drawer.total_qty)} pieces</span>
      <span class="badge">${drawLoadLabel(drawer.load_pct)}</span>
    </div>
    <div class="load-block">
      <div class="load-track">
        <div class="load-fill" style="width:${fillWidth}%; background:${drawer.group_color}"></div>
      </div>
      <div class="load-caption">Estimated load: ${drawer.load_pct}% of the average ${drawer.size} drawer target</div>
    </div>
    ${noteHtml}
    <div class="detail-parts">${partRows}</div>
  `;
  detail.querySelectorAll('.detail-part').forEach(btn => {
    btn.addEventListener('click', () => {
      const part = partsData.find(p => p.part_id === btn.dataset.partId);
      if (!part) return;
      selectedPartId = part.part_id;
      renderDrawerDetail(drawerKey);
      setTab('parts');
      renderPartsGrid();
      requestAnimationFrame(() => {
        document.querySelector(`.part-card[data-part-id="${CSS.escape(part.part_id)}"]`)?.scrollIntoView({behavior:'smooth', block:'center'});
      });
    });
  });
}
function refreshDrawerSelection(scrollIntoView = false){
  document.querySelectorAll('.drawer').forEach(btn => {
    btn.classList.toggle('selected', btn.dataset.drawer === selectedDrawerKey);
  });
  if (selectedDrawerKey) renderDrawerDetail(selectedDrawerKey);
  if (scrollIntoView) {
    const el = document.querySelector(`.drawer[data-drawer="${CSS.escape(selectedDrawerKey)}"]`);
    if (el){
      el.classList.add('pulse');
      setTimeout(() => el.classList.remove('pulse'), 1100);
      el.scrollIntoView({behavior:'smooth', block:'center', inline:'center'});
    }
  }
}
function selectDrawer(drawerKey, partId = null, openCabinet = false){
  selectedDrawerKey = drawerKey;
  selectedPartId = partId;
  if (openCabinet) setTab('cabinet');
  refreshDrawerSelection(openCabinet);
  renderPartsGrid();
}
function populateFilters(){
  const cabinetSelect = document.getElementById('cabinet-filter');
  ['Black','Red'].forEach(name => {
    cabinetSelect.insertAdjacentHTML('beforeend', `<option value="${name}">${name} cabinet</option>`);
  });
  const groupSelect = document.getElementById('group-filter');
  groupOrder
    .filter(group => partsData.some(p => p.broad_group === group))
    .forEach(group => {
      groupSelect.insertAdjacentHTML('beforeend', `<option value="${escapeHtml(group)}">${escapeHtml(group)}</option>`);
    });
    
  const familySelect = document.getElementById('family-filter');
  const uniqueFamilies = [...new Set(Object.values(colorFamilies)), 'Transparents'].sort((a,b) => a.localeCompare(b));
  uniqueFamilies.forEach(fam => {
    familySelect.insertAdjacentHTML('beforeend', `<option value="${escapeHtml(fam)}">${escapeHtml(fam)}</option>`);
  });
}

function updateColorOptions(familyFilter = '') {
  const colorSelect = document.getElementById('color-filter');
  const currentVal = colorSelect.value;
  colorSelect.innerHTML = '<option value="">All colors</option>';
  
  let uniqueColors = [...new Set(partsData.map(p => p.color))].sort((a,b) => a.localeCompare(b));
  if (familyFilter) {
    uniqueColors = uniqueColors.filter(c =>
      familyFilter === 'Transparents' ? c.startsWith('Trans-') : colorFamilies[c] === familyFilter
    );
  }
  
  uniqueColors.forEach(color => {
    const isMatchedFam = colorFamilies[color] ? ` (${colorFamilies[color]})` : '';
    colorSelect.insertAdjacentHTML('beforeend', `<option value="${escapeHtml(color)}">${escapeHtml(color)}${familyFilter ? '' : isMatchedFam}</option>`);
  });
  
  if (uniqueColors.includes(currentVal)) {
    colorSelect.value = currentVal;
  }
}

function currentFilteredParts(){
  const term = document.getElementById('search-input').value.trim().toLowerCase();
  const cabinetValue = document.getElementById('cabinet-filter').value;
  const sizeValue = document.getElementById('size-filter').value;
  const groupValue = document.getElementById('group-filter').value;
  const familyValue = document.getElementById('family-filter').value;
  const colorValue = document.getElementById('color-filter').value;
  let filtered = partsData.filter(part => {
    const hay = [
      part.part_number,
      part.description,
      part.color,
      part.drawer_code,
      part.cabinet,
      part.broad_group,
      part.class_name
    ].join(' ').toLowerCase();
    const matchesTerm = !term || hay.includes(term);
    const matchesCabinet = !cabinetValue || part.cabinet === cabinetValue;
    const matchesSize = !sizeValue || part.drawer_size === sizeValue;
    const matchesGroup = !groupValue || part.broad_group === groupValue;
    const matchesFamily = !familyValue
      || (familyValue === 'Transparents' ? part.color.startsWith('Trans-') : colorFamilies[part.color] === familyValue);
    const matchesColor = !colorValue || part.color === colorValue;
    return matchesTerm && matchesCabinet && matchesSize && matchesGroup && matchesFamily && matchesColor;
  });
  const sortValue = document.getElementById('sort-filter').value;
  if (sortValue === 'description'){
    filtered.sort((a,b) => a.description.localeCompare(b.description) || a.color.localeCompare(b.color));
  } else if (sortValue === 'qty'){
    filtered.sort((a,b) => b.qty - a.qty || a.description.localeCompare(b.description));
  } else if (sortValue === 'color'){
    filtered.sort((a,b) => a.color.localeCompare(b.color) || a.description.localeCompare(b.description));
  } else {
    filtered.sort((a,b) => a.drawer_order - b.drawer_order || a.description.localeCompare(b.description) || a.color.localeCompare(b.color));
  }
  return filtered;
}
function partCardMarkup(part){
  const drawer = drawersByKey.get(part.drawer_key);
  const selected = selectedPartId ? (selectedPartId === part.part_id) : (selectedDrawerKey === part.drawer_key);
  return `<div class="part-card ${selected ? 'selected' : ''}" data-part-id="${part.part_id}" style="--card-accent:${part.group_color}" tabindex="0" role="button">
    <div class="part-top">
      <div class="icon-shell">${partSvg(part)}</div>
      <div>
        <div class="part-title">${escapeHtml(part.description)}</div>
        <div class="part-color">${colorSwatch(part.color_hex, part.color)}${escapeHtml(part.color)}</div>
        <div class="part-drawer">${escapeHtml(part.drawer_code)} · ${escapeHtml(groupShort[part.broad_group] || part.broad_group)}</div>
      </div>
    </div>
    <div class="part-badges">
      <span class="part-badge">Qty ${formatNumber(part.qty)}</span>
      <span class="part-badge mono">#${escapeHtml(part.part_number)}</span>
      <span class="part-badge">${escapeHtml(drawer.size)}</span>
    </div>
  </div>`;
}
function renderLegend(){
  const legend = document.getElementById('legend-row');
  legend.innerHTML = groupOrder
    .filter(group => drawersData.some(d => d.group === group))
    .map(group => {
      const match = drawersData.find(d => d.group === group);
      return `<span class="legend-pill"><span class="dot" style="background:${match.group_color}"></span>${escapeHtml(groupShort[group] || group)}</span>`;
    }).join('');
}
function renderPartsGrid(){
  const grid = document.getElementById('parts-grid');
  const filtered = currentFilteredParts();
  document.getElementById('results-count').textContent = `${formatNumber(filtered.length)} of ${formatNumber(partsData.length)} lots shown`;
  if (!filtered.length){
    grid.innerHTML = `<div class="empty-results">No parts match the current search/filter combination.</div>`;
    return;
  }
  grid.innerHTML = filtered.map(partCardMarkup).join('');
  grid.querySelectorAll('.part-card').forEach(card => {
    card.addEventListener('click', (e) => {
      const existing = card.querySelector('.part-tooltip');
      if (existing) {
        existing.remove();
        return;
      }
      document.querySelectorAll('.part-tooltip').forEach(tt => tt.remove());

      const part = partsData.find(p => p.part_id === card.dataset.partId);
      if (!part) return;
      const drawer = drawersByKey.get(part.drawer_key);

      const tooltipHTML = `
        <div class="part-tooltip">
          <button class="tooltip-close" aria-label="Close tooltip">&times;</button>
          <div class="tooltip-label">Location</div>
          <div style="display:flex; gap:14px; align-items:center; margin-bottom:14px;">
            ${cabinetMinimapSvg(part.cabinet, part.drawer_code)}
            <div>
              <div class="tooltip-cabinet">${escapeHtml(part.cabinet)} Cabinet</div>
              <div class="tooltip-drawer" style="margin-bottom:0;">Drawer <strong>${escapeHtml(part.drawer_code)}</strong> &middot; ${escapeHtml(drawer.size)}</div>
            </div>
          </div>
          <button class="tooltip-jump" data-drawer-key="${escapeHtml(part.drawer_key)}" data-part-id="${escapeHtml(part.part_id)}">View inside cabinet &rarr;</button>
        </div>
      `;
      card.insertAdjacentHTML('beforeend', tooltipHTML);

      const tooltip = card.querySelector('.part-tooltip');
      tooltip.addEventListener('click', (ev) => ev.stopPropagation());
      tooltip.querySelector('.tooltip-close').addEventListener('click', () => tooltip.remove());
      tooltip.querySelector('.tooltip-jump').addEventListener('click', (ev) => {
        selectDrawer(ev.currentTarget.dataset.drawerKey, ev.currentTarget.dataset.partId, true);
      });
    });
  });

  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') {
      document.querySelectorAll('.part-tooltip').forEach(tt => tt.remove());
    }
  });
}
function bindToolbar(){
  ['search-input','cabinet-filter','size-filter','group-filter','sort-filter'].forEach(id => {
    document.getElementById(id).addEventListener('input', renderPartsGrid);
    document.getElementById(id).addEventListener('change', renderPartsGrid);
  });
  
  const famFilter = document.getElementById('family-filter');
  const colFilter = document.getElementById('color-filter');
  
  famFilter.addEventListener('change', (e) => {
    updateColorOptions(e.target.value);
    renderPartsGrid();
  });
  
  colFilter.addEventListener('change', (e) => {
    const color = e.target.value;
    if (color && colorFamilies[color]) {
      famFilter.value = colorFamilies[color];
      updateColorOptions(colorFamilies[color]);
      colFilter.value = color; // keep it selected
    }
    renderPartsGrid();
  });
}
function bindTabs(){
  document.querySelectorAll('.tab').forEach(tab => {
    tab.addEventListener('click', () => setTab(tab.dataset.tab));
  });
}
function initAi() {
  const overlay = document.getElementById('drag-overlay');
  const modal = document.getElementById('ai-modal');
  const btnClose = document.getElementById('btn-close-ai');
  const btnScan = document.getElementById('btn-scan');
  const fileInput = document.getElementById('file-upload');
  const preview = document.getElementById('ai-preview');
  const loading = document.getElementById('ai-loading');
  const resultsCol = document.getElementById('ai-results');

  let dragCounter = 0;
  document.addEventListener('dragenter', (e) => {
    e.preventDefault();
    dragCounter++;
    overlay.classList.add('active');
  });
  document.addEventListener('dragleave', (e) => {
    e.preventDefault();
    dragCounter--;
    if (dragCounter === 0) overlay.classList.remove('active');
  });
  document.addEventListener('dragover', (e) => e.preventDefault());
  document.addEventListener('drop', (e) => {
    e.preventDefault();
    dragCounter = 0;
    overlay.classList.remove('active');
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      processImage(e.dataTransfer.files[0]);
    }
  });

  btnScan.addEventListener('click', () => fileInput.click());
  fileInput.addEventListener('change', (e) => {
    if (e.target.files && e.target.files.length > 0) {
      processImage(e.target.files[0]);
    }
    fileInput.value = '';
  });

  btnClose.addEventListener('click', () => modal.classList.remove('active'));

  async function processImage(file) {
    if (!file.type.startsWith('image/')) {
      alert('Please upload an image file.');
      return;
    }
    
    modal.classList.add('active');
    loading.style.display = 'flex';
    resultsCol.innerHTML = '';
    
    const reader = new FileReader();
    reader.onload = async (e) => {
      const dataUrl = e.target.result;
      preview.src = dataUrl;
      const base64Data = dataUrl.split(',')[1];
      
      try {
        const results = await identifyLegoParts(base64Data, file.type, partsData);
        renderAiResults(results);
      } catch (err) {
        resultsCol.innerHTML = `<div style="color:red; padding:16px;">Error: ${escapeHtml(err.message)}</div>`;
      } finally {
        loading.style.display = 'none';
      }
    };
    reader.readAsDataURL(file);
  }
}

function renderAiResults(results) {
  const resultsCol = document.getElementById('ai-results');
  if (!results || results.length === 0) {
    resultsCol.innerHTML = `<div style="padding:16px; color:var(--muted);">No LEGO parts identified. Try another image!</div>`;
    return;
  }
  
  setTab('cabinet');
  selectedDrawerKey = null; 
  selectedPartId = null; 
  refreshDrawerSelection(true);
  
  const matchedKeys = [];
  let html = `<h3 style="margin-bottom:8px; font-size:18px;">Identified Parts</h3>`;
  
  results.forEach(res => {
    const part = partsData.find(p => p.part_id === res.id);
    if (!part) return; 
    
    matchedKeys.push(part.drawer_key);
    html += `
      <div class="ai-result-item" data-drawer-key="${escapeHtml(part.drawer_key)}" data-part-id="${escapeHtml(part.part_id)}">
        <div class="icon-shell" style="width:48px;height:48px;">
          ${partSvg(part)}
        </div>
        <div>
          <div style="font-weight:800; font-size:14px; color:#2a3550;">${escapeHtml(part.description)}</div>
          <div class="ai-result-meta">${escapeHtml(part.color)} &middot; Found: ${res.qty}</div>
        </div>
        <div style="text-align:right;">
          <div style="font-weight:800; font-size:16px; color:#2b6df6;">${escapeHtml(part.drawer_code)}</div>
          <div class="ai-result-meta">${escapeHtml(part.cabinet)}</div>
        </div>
      </div>
    `;
  });

  // All values in the template above are escaped via escapeHtml() — safe to assign
  resultsCol.innerHTML = html;
  resultsCol.querySelectorAll('.ai-result-item').forEach(item => {
    item.addEventListener('click', () => {
      selectDrawer(item.dataset.drawerKey, item.dataset.partId, true);
      document.getElementById('ai-modal').classList.remove('active');
    });
  });
  
  if (matchedKeys.length > 0) {
    document.querySelectorAll('.drawer').forEach(el => {
      if (matchedKeys.includes(el.dataset.drawer)) {
        el.classList.remove('pulse');
        void el.offsetWidth;
        el.classList.add('pulse');
        el.classList.add('selected');
      } else {
        el.classList.remove('selected');
        el.classList.remove('pulse');
      }
    });
  }
}

function init(){
  renderCabinet('Black');
  renderCabinet('Red');
  populateFilters();
  updateColorOptions('');
  renderLegend();
  bindToolbar();
  bindTabs();
  refreshDrawerSelection(false);
  renderPartsGrid();
  initAi();
}
init();